const results = $input.first().json.results || [];
const renovaciones = [];
results.forEach(ps => {
  const props = ps.properties;
  const renovacion = {
    ps_id: ps.id,
    cups: props['CUPS']?.title[0]?.plain_text || '',
    nombre_titular: props['Nombre Titular']?.rich_text[0]?.plain_text || '',
    fecha_renovacion: props['Fecha Renovacion']?.date?.start || '',
    dias_para_vencer: Math.ceil((new Date(props['Fecha Renovacion']?.date?.start) - new Date()) / (1000 * 60 * 60 * 24)),
    tarifa_actual: props['Tarifa Actual']?.rich_text[0]?.plain_text || '',
    comercializadora_actual: props['Comercializadora Actual']?.rich_text[0]?.plain_text || '',
    permanencia_meses: props['Permanencia Meses']?.number || 0
  };
  renovaciones.push(renovacion);
});
return [{
  json: {
    event_type: 'renovacion_proxima',
    timestamp: new Date().toISOString(),
    data: { renovaciones: renovaciones, total: renovaciones.length }
  }
}];

const data = $input.first().json.data;
const renovaciones = data.renovaciones || [];
if (renovaciones.length === 0) {
  return [{ json: { status: 'no_renovations' } }];
}
let mensaje = 'RENOVACIONES PROXIMAS (proximos 30 dias)\n\n';
renovaciones.forEach((r, idx) => {
  const dias = r.dias_para_vencer;
  mensaje += `${idx+1}. ${r.nombre_titular}\n`;
  mensaje += `   CUPS: ${r.cups}\n`;
  mensaje += `   Vence: ${r.fecha_renovacion} (${dias} dias)\n`;
  mensaje += `   Tarifa: ${r.tarifa_actual} (${r.comercializadora_actual})\n\n`;
});
return [{
  json: { event_type: 'renovacion_proxima', total_renovaciones: renovaciones.length, renovaciones: renovaciones, mensaje_whatsapp: mensaje, status: 'ready_to_notify' }
}];

const timestamp = new Date().toISOString();
const total = $input.first().json.total_renovaciones;
return [{ json: { log: { timestamp: timestamp, total_renovaciones: total, status: total > 0 ? 'notificacion_enviada' : 'sin_renovaciones' } } }];
